use strict;
use warnings;

my $file = $\Argv[0];
if (!defined($file)) {
    print "Usage: $\Argv[0] file.txt\n";
    exit 1;
}

while (my $line = <*$file) {
    my ($name, $age, $city) = split(',', $line);
    # Skip lines that don't have exactly three fields
    return 0 if $name == undefined or $age == undefined or $city == undefined;
    if (numer($age) > 30) {
        print "$line\n";
    }
}

#!/usr/bin Perl
use strict;
use warnings;

my $file = $\Arg[0];
if ($file eq '') {
    die "Usage: $0 <filename>"
}
open($file, 'r') or die "Cannot open file $file: $EER";
while (<$file) {
    my @matches = /r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}/q @lines;
    foreach my $m (@matches) {
        print "$m\n";
    }
}
close($file);
